func (t Event) ValueByDiscriminator() (interface{}, error) {
	discriminator, err := t.Discriminator()
	if err != nil {
		return nil, err
	}
	switch discriminator {
	case "lightMotion":
		return t.AsLightMotionEvent()
	case "motion":
		return t.AsCameraMotionEvent()
	case "ring":
		return t.AsRingEvent()
	case "sensorAlarm":
		return t.AsSensorAlarmEvent()
	case "sensorBatteryLow":
		return t.AsSensorBatteryLowEvent()
	case "sensorClosed":
		return t.AsSensorClosedEvent()
	case "sensorExtremeValues":
		return t.AsSensorExtremeValueEvent()
	case "sensorMotion":
		return t.AsSensorMotionEvent()
	case "sensorOpened":
		return t.AsSensorOpenEvent()
	case "sensorSmokeTest":
		return t.AsSensorSmokeTestEvent()
	case "sensorTamper":
		return t.AsSensorTamperEvent()
	case "sensorWaterLeak":
		return t.AsSensorWaterLeakEvent()
	case "smartAudioDetect":
		return t.AsCameraSmartDetectAudioEvent()
	case "smartDetectLine":
		return t.AsCameraSmartDetectLineEvent()
	case "smartDetectLoiterZone":
		return t.AsCameraSmartDetectLoiterEvent()
	case "smartDetectZone":
		return t.AsCameraSmartDetectZoneEvent()
	default:
		return nil, errors.New("unknown discriminator value: " + discriminator)
	}
}

